(function() { try {
// Register GSAP Plugins
gsap.registerPlugin(ScrollTrigger);

document.addEventListener('DOMContentLoaded', () => {
    // 1. Initialize Lenis Smooth Scrolling
    const lenis = new Lenis({
        duration: 1.2,
        easing: (t) => Math.min(1, 1.001 - Math.pow(2, -10 * t)),
        direction: 'vertical',
        gestureDirection: 'vertical',
        smooth: true,
        mouseMultiplier: 1,
        smoothTouch: false,
        touchMultiplier: 2,
        infinite: false,
    });

    function raf(time) {
        lenis.raf(time);
        requestAnimationFrame(raf);
    }
    requestAnimationFrame(raf);

    // Integrate Lenis with GSAP ScrollTrigger
    lenis.on('scroll', ScrollTrigger.update);
    gsap.ticker.add((time) => {
        lenis.raf(time * 1000);
    });
    gsap.ticker.lagSmoothing(0);

    // 2. Mobile Menu Toggle
    const mobileMenuBtn = document.getElementById('mobile-menu-btn');
    const mobileMenu = document.getElementById('mobile-menu');

    if (mobileMenuBtn && mobileMenu) {
        mobileMenuBtn.addEventListener('click', () => {
            mobileMenu.classList.toggle('active');
        });

        // Close mobile menu when clicking outside
        document.addEventListener('click', (e) => {
            if (!mobileMenuBtn.contains(e.target) && !mobileMenu.contains(e.target)) {
                mobileMenu.classList.remove('active');
            }
        });
    }

    // 3. Navigation Styling on Scroll
    const nav = document.getElementById('main-nav');
    const navLogoText = document.querySelector('.nav-logo-text');

    window.addEventListener('scroll', () => {
        if (window.scrollY > 100) {
            nav.classList.add('glass', 'py-4', 'shadow-xl');
            nav.classList.remove('py-6');
            if (navLogoText) navLogoText.classList.remove('text-white');
            if (navLogoText) navLogoText.classList.add('text-blue-950');
            document.querySelectorAll('.nav-link').forEach(link => {
                link.classList.remove('text-white/80');
                link.classList.add('text-blue-950/70');
            });
        } else {
            nav.classList.remove('glass', 'py-4', 'shadow-xl');
            nav.classList.add('py-6');
            if (navLogoText) navLogoText.classList.add('text-white');
            if (navLogoText) navLogoText.classList.remove('text-blue-950');
            document.querySelectorAll('.nav-link').forEach(link => {
                link.classList.add('text-white/80');
                link.classList.remove('text-blue-950/70');
            });
        }
    });

    // 4. Parallax Hero Animation
    gsap.to('.parallax-bg', {
        scrollTrigger: {
            trigger: '.hero-jumbotron',
            start: 'top top',
            end: 'bottom top',
            scrub: true
        },
        y: 200,
        scale: 1.2
    });

    // 5. Reveal Animations
    const revealItems = gsap.utils.toArray('.reveal-up');
    revealItems.forEach((el) => {
        gsap.fromTo(el,
            { y: 60, opacity: 0 },
            {
                y: 0,
                opacity: 1,
                duration: 1.2,
                ease: "power4.out",
                scrollTrigger: {
                    trigger: el,
                    start: "top 85%",
                    toggleActions: "play none none none"
                }
            }
        );
    });

    // 6. Hero Search Form - handled by inline script in blade template

    // 7. FAQ Accordion Logic
    const faqQuestions = document.querySelectorAll('.faq-question');
    faqQuestions.forEach(q => {
        q.addEventListener('click', () => {
            const parent = q.parentElement;
            const answer = q.nextElementSibling;
            const chevron = q.querySelector('.faq-chevron');

            // Close others
            document.querySelectorAll('.faq-item').forEach(item => {
                if (item !== parent && item.classList.contains('active')) {
                    item.classList.remove('active');
                    gsap.to(item.querySelector('.faq-answer'), { height: 0, duration: 0.4, ease: "power2.inOut" });
                    gsap.to(item.querySelector('.faq-chevron'), { rotation: 0, duration: 0.4 });
                }
            });

            // Toggle current
            const isActive = parent.classList.toggle('active');
            gsap.to(answer, { height: isActive ? 'auto' : 0, duration: 0.4, ease: "power2.inOut" });
            gsap.to(chevron, { rotation: isActive ? 180 : 0, duration: 0.4 });
        });
    });

    // 8. Animated Counters
    const counters = document.querySelectorAll('.counter');
    counters.forEach(counter => {
        const target = +counter.getAttribute('data-target');
        const suffix = counter.getAttribute('data-suffix') || '';

        ScrollTrigger.create({
            trigger: counter,
            start: "top 90%",
            onEnter: () => {
                let count = { val: 0 };
                gsap.to(count, {
                    val: target,
                    duration: 2,
                    ease: "power2.out",
                    onUpdate: () => {
                        counter.innerText = Math.floor(count.val).toLocaleString() + suffix;
                    }
                });
            }
        });
    });

    // 9. Checkout Page Logic
    const planCards = document.querySelectorAll('.plan-card');
    const vinContainer = document.getElementById('vin-inputs-container');
    const maxVinsText = document.getElementById('max-vins-text');
    const summaryPlanName = document.getElementById('summary-plan-name');
    const summaryVinsCount = document.getElementById('summary-vins-count');
    const summaryTotal = document.getElementById('summary-total');

    const updateCheckoutPlan = (card) => {
        if (!card) return;

        // UI Update
        planCards.forEach(c => c.classList.remove('selected', 'border-blue-900', 'bg-blue-50/50'));
        card.classList.add('selected', 'border-blue-900', 'bg-blue-50/50');

        const plan = card.getAttribute('data-plan');
        const price = card.getAttribute('data-price');
        const vinsCount = parseInt(card.getAttribute('data-vins'));

        // Update Summary
        if (summaryPlanName) summaryPlanName.innerText = plan.charAt(0).toUpperCase() + plan.slice(1);
        if (summaryVinsCount) summaryVinsCount.innerText = vinsCount;
        if (summaryTotal) summaryTotal.innerText = `$${price}`;
        if (maxVinsText) maxVinsText.innerText = vinsCount;

        // Update VIN Inputs
        if (vinContainer) {
            const currentInputs = vinContainer.querySelectorAll('.vin-input-group');
            const currentCount = currentInputs.length;

            if (vinsCount > currentCount) {
                for (let i = currentCount; i < vinsCount; i++) {
                    const div = document.createElement('div');
                    div.className = 'vin-input-group reveal-up opacity-0';
                    div.innerHTML = `
                        <label class="block text-xs font-bold uppercase tracking-widest text-gray-400 mb-2">HIN #${i + 1}</label>
                        <input type="text" class="vin-input-field w-full bg-gray-50 border-0 focus:ring-2 focus:ring-blue-500 rounded-xl p-4 transition" placeholder="Enter 12-character HIN">
                    `;
                    vinContainer.appendChild(div);
                    gsap.to(div, { opacity: 1, y: 0, duration: 0.5, delay: (i - currentCount) * 0.1 });
                }
            } else if (vinsCount < currentCount) {
                for (let i = currentCount - 1; i >= vinsCount; i--) {
                    currentInputs[i].remove();
                }
            }
        }
    };

    planCards.forEach(card => {
        card.addEventListener('click', () => updateCheckoutPlan(card));
    });

    // Country & State Logic - handled by inline script in blade template

    // Checkout Form Submission - handled by inline script in blade template
});

} catch(e) { console.warn('Error in https://marinehistorychecks.com/public/boat/main.js:', e); } })();

