(function() { try {
// From https://marinehistorychecks.com
document.getElementById('hero-search-form').addEventListener('submit', function(e) {

            const isMobile = window.innerWidth < 768;

            let vin, email, country;

            if (isMobile) {
                vin = document.getElementById('mobile-vin').value;
                email = document.getElementById('mobile-email').value;
                country = document.getElementById('mobile-country').value;
            } else {
                vin = document.getElementById('desktop-vin').value;
                email = document.getElementById('desktop-email').value;
                country = document.getElementById('desktop-country').value;
            }

            if (!vin || !vin.trim()) {
                e.preventDefault();
                alert('Please enter a HIN (Hull Identification Number)');
                return false;
            }

            if (!email || !email.trim()) {
                e.preventDefault();
                alert('Please enter your email address');
                return false;
            }

            const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
            if (!emailRegex.test(email)) {
                e.preventDefault();
                alert('Please enter a valid email address');
                return false;
            }

            if (!country) {
                e.preventDefault();
                alert('Please select a country');
                return false;
            }

            document.getElementById('hidden-vin').value = vin;
            document.getElementById('hidden-email').value = email;
            document.getElementById('hidden-country').value = country;

            return true;
        });

} catch(e) { console.warn('Error in inline script:', e); } })();

